import Foundation

enum APIError: Error {
    case invalidURL
    case invalidResponse
}

final class NetworkService: ObservableObject {
    @Published var apiResponse: String = ""
    @Published var legacyResponse: String = ""

    private let session: URLSession = {
        let configuration = URLSessionConfiguration.default
        configuration.waitsForConnectivity = true
        configuration.timeoutIntervalForRequest = 30
        configuration.timeoutIntervalForResource = 60
        return URLSession(configuration: configuration)
    }()

    @MainActor
    func fetchAll() async {
        async let api = fetch(from: "https://api.example.com")
        async let legacy = fetch(from: "http://legacy.internal")

        do {
            let (apiResult, legacyResult) = try await (api, legacy)
            apiResponse = apiResult
            legacyResponse = legacyResult
        } catch {
            apiResponse = "Error: \(error.localizedDescription)"
            legacyResponse = "Error: \(error.localizedDescription)"
        }
    }

    private func fetch(from urlString: String) async throws -> String {
        guard let url = URL(string: urlString) else {
            throw APIError.invalidURL
        }

        let (data, response) = try await session.data(from: url)

        guard let httpResponse = response as? HTTPURLResponse else {
            throw APIError.invalidResponse
        }

        let body = String(data: data, encoding: .utf8) ?? "<non-UTF8 response>"
        return "[\(httpResponse.statusCode)] \(body)"
    }
}

import SwiftUI

struct ContentView: View {
    @StateObject private var service = NetworkService()

    var body: some View {
        NavigationView {
            ScrollView {
                VStack(alignment: .leading, spacing: 16) {
                    Button("Fetch From Servers") {
                        Task {
                            await service.fetchAll()
                        }
                    }

                    Group {
                        Text("API Server")
                            .font(.headline)
                        Text(service.apiResponse.isEmpty ? "No response yet" : service.apiResponse)
                            .font(.body)
                            .textSelection(.enabled)
                    }

                    Group {
                        Text("Legacy On-Premise")
                            .font(.headline)
                        Text(service.legacyResponse.isEmpty ? "No response yet" : service.legacyResponse)
                            .font(.body)
                            .textSelection(.enabled)
                    }
                }
                .padding()
            }
            .navigationTitle("Connectivity Test")
        }
    }
}